def compute_volume_metrics(
    incidents: list[dict],
    api_requests_billions: float,
    period_days: int,
) -> dict:
    by_severity = {}
    for p in ("p0", "p1", "p2", "p3"):
        by_severity[p] = sum(1 for i in incidents if i["severity"] == p)
    total = len(incidents)
    repeat = sum(1 for i in incidents if i.get("is_repeat", False))
    return {
        "total": total,
        "by_severity": by_severity,
        "incidents_per_week": round(total / (period_days / 7), 1),
        "incident_rate_per_B_requests": round(total / api_requests_billions, 2) if api_requests_billions else None,
        "repeat_count": repeat,
        "repeat_rate": round(repeat / total, 3) if total else 0,
    }

def detect_spike(
    weekly_counts: list[int],
    baseline_window_weeks: int = 4,
    spike_multiplier: float = 2.0,
) -> list[int]:
    spike_weeks = []
    for i in range(baseline_window_weeks, len(weekly_counts)):
        baseline = sum(weekly_counts[i - baseline_window_weeks:i]) / baseline_window_weeks
        if baseline > 0 and weekly_counts[i] >= baseline * spike_multiplier:
            spike_weeks.append(i)
    return spike_weeks

def detect_drift(
    quarterly_counts: list[int],
    min_quarters: int = 3,
) -> dict:
    if len(quarterly_counts) < min_quarters:
        return {"insufficient_data": True}
    # Simple linear regression slope
    n = len(quarterly_counts)
    x = list(range(n))
    x_mean = sum(x) / n
    y_mean = sum(quarterly_counts) / n
    numerator = sum((xi - x_mean) * (yi - y_mean) for xi, yi in zip(x, quarterly_counts))
    denominator = sum((xi - x_mean) ** 2 for xi in x)
    slope = numerator / denominator if denominator else 0
    return {
        "slope_per_quarter": round(slope, 2),
        "trend": "increasing" if slope > 0.5 else "decreasing" if slope < -0.5 else "stable",
        "magnitude": "significant" if abs(slope) > 1.0 else "mild",
    }

from collections import Counter

def category_decomposition(
    incidents: list[dict],
    period_label: str,
) -> dict:
    cats = Counter(i.get("failure_category", "unknown") for i in incidents)
    total = len(incidents)
    return {
        "period": period_label,
        "total": total,
        "by_category": {
            cat: {
                "count": count,
                "pct": round(count / total * 100, 1),
            }
            for cat, count in cats.most_common()
        },
    }

def category_qoq_delta(q_current: dict, q_prior: dict) -> dict:
    deltas = {}
    all_cats = set(q_current["by_category"]) | set(q_prior["by_category"])
    for cat in all_cats:
        curr = q_current["by_category"].get(cat, {"count": 0})["count"]
        prior = q_prior["by_category"].get(cat, {"count": 0})["count"]
        deltas[cat] = {
            "current": curr,
            "prior": prior,
            "delta": curr - prior,
            "pct_change": round((curr - prior) / prior * 100, 1) if prior else None,
        }
    return deltas

def compute_oncall_load(
    incidents: list[dict],
    oncall_schedule: list[dict],
) -> list[dict]:
    load_by_shift = {}
    for shift in oncall_schedule:
        engineer = shift["engineer"]
        start = shift["start"]
        end = shift["end"]
        shift_incidents = [
            i for i in incidents
            if start <= i["declared_at"] <= end
        ]
        p0p1 = [i for i in shift_incidents if i["severity"] in ("p0", "p1")]
        night = [
            i for i in p0p1
            if is_outside_business_hours(i["declared_at"], engineer_timezone(engineer))
        ]
        load_by_shift[shift["id"]] = {
            "engineer": engineer,
            "start": start,
            "total_incidents": len(shift_incidents),
            "p0p1_count": len(p0p1),
            "night_page_count": len(night),
            "night_page_pct": len(night) / len(p0p1) if p0p1 else 0,
            "fatigue_flag": len(p0p1) > 5 or len(night) > 2,
        }
    return list(load_by_shift.values())

